import{c as a,Q as t,j as i,m as o}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"ADR-003 — Vite as bundler","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-003.md","filePath":"adr/ADR-003.md"}'),n={name:"adr/ADR-003.md"};function r(s,e,l,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-003-—-vite-as-bundler" tabindex="-1">ADR-003 — Vite as bundler <a class="header-anchor" href="#adr-003-—-vite-as-bundler" aria-label="Permalink to &quot;ADR-003 — Vite as bundler&quot;">​</a></h1><blockquote><p>Status · <strong>Superseded by ADR-012 (SvelteKit, which bundles via Vite — same answer, decided downstream)</strong> Date · 2026-04-01 · Superseded April 2026 TA anchor · §stack</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>A bundler is needed to handle ES modules, asset bundling (fonts, textures, logos), and production builds.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Vite.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Fast dev server with native ES module support. Zero-config for simple projects. Good Three.js compatibility. Widely used and well-maintained. The prototype code uses vanilla ES modules — Vite handles this without configuration.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>Webpack — more configuration overhead; slower dev server; no clear benefit for this project&#39;s size.</li><li>esbuild directly — lacks the dev server and HMR that make development practical.</li><li>No bundler (ES modules served directly) — works for development; breaks for production asset bundling, code splitting, and offline support.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: fast dev iteration; minimal configuration; handles asset pipeline cleanly. Negative: Vite major versions occasionally have breaking changes; pin the version.</p>',12)])])}const b=a(n,[["render",r]]);export{p as __pageData,b as default};
